VALUES
  ('promotion-6e2f88c7-moex-00024', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '下列關於分別共有物處分之敘述，何者錯誤？', '["分別共有之動產，各共有人得自由處分其應有部分", "分別共有之動產，對共有物之處分，應得共有人全體之同意", "分別共有之不動產，對共有物之處分，應得共有人全體之同意", "分別共有不動產之處分，除其應有部分合計超過三分之二，其人數不予計算者外，應以共有人 過半數及其應有部分合計過半數之同意為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00025', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲僅有一子乙，某日甲死亡，留有現金新臺幣（下同）500萬元，丙對甲有1,000萬元債權，當乙 作出下列何種行為時，仍得主張民法第1148條第2項規定之限定責任？', '["乙將該500萬元提領並私藏於朋友家", "乙於甲生前對甲恐嚇：不給錢，我就殺了你，甲聞後心生畏懼未予理會", "乙於甲死亡後向法院陳報遺產清冊，記載甲僅遺留現金50萬元", "乙與丙勾結製造對甲之假債權400萬元，並先對丙清償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00026', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲男乙女為夫妻，二人為某特定目的而通謀虛偽離婚，並辦理離婚登記。嗣後，於分居期間甲邂 逅丙女，丙信賴甲乙之離婚登記，而與甲結婚，並辦理結婚登記。下列敘述何者正確？', '["丙信賴甲乙之離婚登記，甲丙婚姻有效", "丙受甲詐欺而結婚，得撤銷其婚姻", "甲乙婚姻關係存在", "甲乙婚姻視為消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00027', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲為乙男之非婚生子女，甲於乙死亡前，均無任何接觸。下列敘述何者正確？', '["乙以遺囑認領甲，甲不知，則不生認領效力", "乙以遺囑認領甲，並就遺贈附停止條件，條件成就前，不生認領效力", "甲於乙死亡後，得向乙之繼承人提起認領之訴", "甲其實曾寫信要求乙認領，乙於死亡前回信承諾，因不符遺囑要式之規定，不生認領效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00028', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲男乙女於民國（下同）100年1月間結婚，未約定夫妻財產制，甲乙於111年1月間兩願離婚。 甲婚前財產有一筆存款新臺幣（下同）200萬元，婚後甲之薪資工作所得為800萬元，及負債200 萬元未清償。乙婚前財產有一筆存款300萬元，婚後乙之薪資工作所得為300萬元，及繼承900 萬元，無負債。關於甲乙間得請求多少剩餘財產差額之平均分配，下列敘述何者正確？', '["甲得向乙主張300萬元", "甲得向乙主張350萬元", "乙得向甲主張100萬元", "乙得向甲主張150萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00029', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '下列關於拋棄繼承之敘述，何者錯誤？', '["繼承人應自繼承開始前3個月內為繼承之拋棄", "繼承之拋棄，溯及於繼承開始時，發生效力", "繼承人應以書面，向法院為繼承之拋棄", "拋棄繼承權者，就其所管理之遺產，於其他繼承人或遺產管理人開始管理前，應與處理自己事 務為同一之注意，繼續管理之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00030', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '下列關於共有物保存行為之敘述，何者正確？', '["以共有人過半數及其應有部分合計過半數之同意為之", "共有人數不計，須應有部分合計超過三分之二，始得為之", "共有物之簡易修繕，得由各共有人單獨為之", "須得共有人全體同意，始得為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00031', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲喪妻有乙、丙、丁三子。甲於乙分居時，贈與新臺幣（下同）100萬元，於丙營業時，贈與50 萬元。甲死亡時，留有遺產300萬元。惟甲立遺囑遺贈戊300萬元。戊最多可得多少？', '["300萬元", "200萬元", "150萬元", "100萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00032', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-e6abbdc3', 'sub-promotion-6e2f88c7-03', NULL, 'essay', '試舉例說明在行政機關內部規則的制定上，運用錯誤的立法技術造成民
眾之權益受行政機關內部規則不正當侵害之情事。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "8eef7f432ee6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0408", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "立法程序與技術", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00033', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-e6abbdc3', 'sub-promotion-6e2f88c7-03', NULL, 'essay', '憲法法庭 113 年憲判字第 9 號判決理由中載明：「憲法增修條文第 3 條
第 2 項第 1款明定立法委員係於開會時，始有向行政首長質詢之權，因
此立法委員得行使質詢權之期間，應為立法院開會時，即立法院院會舉
行期間。如係委員會之會議，雖得邀請行政院各部會首長及其所屬公務
員等政府人員到會備詢（憲法第67 條第 2項規定參照），政府人員並應
就立法委員之詢問，為適當說明（釋字第 461號解釋參照），惟立法委員
於此僅享有詢問權，而非質詢權。另質詢權行使之方式，原則上為立法
委員於院會期間，以言詞或書面向行政首長提出質詢內容，受質詢之行
政首長原則上亦應以言詞或書面答復質詢。」試分析本判決中「詢問權」
與「質詢權」之異同。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "8eef7f432ee6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0408", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "立法程序與技術", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL)
